class Ttl:
    def __init__(self):
        raise RuntimeError("Ttl cannot be instantiated directly")

    # Each enum variant is a nested class of the enum itself.
    class DEFAULT:
        def __init__(
            self,
        ):
            pass

        def __str__(self):
            return "Ttl.DEFAULT()".format()

        def __eq__(self, other):
            if not other.is_DEFAULT():
                return False
            return True

    class NO_EXPIRY:
        def __init__(
            self,
        ):
            pass

        def __str__(self):
            return "Ttl.NO_EXPIRY()".format()

        def __eq__(self, other):
            if not other.is_NO_EXPIRY():
                return False
            return True

    class EXPIRE_AFTER_TICKS:
        def __init__(self, *values):
            if len(values) != 1:
                raise TypeError(f"Expected 1 arguments, found {len(values)}")
            self._values = values

        def __getitem__(self, index):
            return self._values[index]

        def __str__(self):
            return f"Ttl.EXPIRE_AFTER_TICKS{self._values!r}"

        def __eq__(self, other):
            if not other.is_EXPIRE_AFTER_TICKS():
                return False
            return self._values == other._values

    # For each variant, we have `is_NAME` and `is_name` methods for easily checking
    # whether an instance is that variant.
    def is_DEFAULT(self) -> bool:
        return isinstance(self, Ttl.DEFAULT)

    def is_default(self) -> bool:
        return isinstance(self, Ttl.DEFAULT)

    def is_NO_EXPIRY(self) -> bool:
        return isinstance(self, Ttl.NO_EXPIRY)

    def is_no_expiry(self) -> bool:
        return isinstance(self, Ttl.NO_EXPIRY)

    def is_EXPIRE_AFTER_TICKS(self) -> bool:
        return isinstance(self, Ttl.EXPIRE_AFTER_TICKS)

    def is_expire_after_ticks(self) -> bool:
        return isinstance(self, Ttl.EXPIRE_AFTER_TICKS)


# Now, a little trick - we make each nested variant class be a subclass of the main
# enum class, so that method calls and instance checks etc will work intuitively.
# We might be able to do this a little more neatly with a metaclass, but this'll do.
Ttl.DEFAULT = type(
    "Ttl.DEFAULT",
    (
        Ttl.DEFAULT,
        Ttl,
    ),
    {},
)  # type: ignore
Ttl.NO_EXPIRY = type(
    "Ttl.NO_EXPIRY",
    (
        Ttl.NO_EXPIRY,
        Ttl,
    ),
    {},
)  # type: ignore
Ttl.EXPIRE_AFTER_TICKS = type(
    "Ttl.EXPIRE_AFTER_TICKS",
    (
        Ttl.EXPIRE_AFTER_TICKS,
        Ttl,
    ),
    {},
)  # type: ignore


class _UniffiConverterTypeTtl(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return Ttl.DEFAULT()
        if variant == 2:
            return Ttl.NO_EXPIRY()
        if variant == 3:
            return Ttl.EXPIRE_AFTER_TICKS(
                _UniffiConverterUInt64.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value.is_DEFAULT():
            return
        if value.is_NO_EXPIRY():
            return
        if value.is_EXPIRE_AFTER_TICKS():
            _UniffiConverterUInt64.check_lower(value._values[0])
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value.is_DEFAULT():
            buf.write_i32(1)
        if value.is_NO_EXPIRY():
            buf.write_i32(2)
        if value.is_EXPIRE_AFTER_TICKS():
            buf.write_i32(3)
            _UniffiConverterUInt64.write(value._values[0], buf)


class _UniffiConverterOptionalUInt32(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiConverterUInt32.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiConverterUInt32.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiConverterUInt32.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")


